#include <bits/stdc++.h>
using namespace std;

int calculateMinimumCutCost(int stickLength, vector<int>& cutPositions) {
    vector<int> cuts;
    cuts.push_back(0);
    for (int cut : cutPositions)
        cuts.push_back(cut);
    cuts.push_back(stickLength);
    sort(cuts.begin(), cuts.end());
    int n = cuts.size();
    vector<vector<int>> dp(n, vector<int>(n, 0));
    for (int length = 2; length < n; length++) {
        for (int i = 0; i + length < n; i++) {
            int j = i + length;
            dp[i][j] = INT_MAX;
            for (int k = i + 1; k < j; k++) {
                int cost = dp[i][k] + dp[k][j] + (cuts[j] - cuts[i]);
                dp[i][j] = min(dp[i][j], cost);
            }
            if (dp[i][j] == INT_MAX)
                dp[i][j] = 0;
        }
    }
    return dp[0][n - 1];
}

