import java.util.*;

class Main {
    public int calculateMinimumCutCost(int stickLength, int[] cutPositions) {
        int n = cutPositions.length + 2;
        int[] cuts = new int[n];
        cuts[0] = 0;
        for (int i = 0; i < cutPositions.length; i++) {
            cuts[i + 1] = cutPositions[i];
        }
        cuts[n - 1] = stickLength;
        Arrays.sort(cuts);
        int[][] dp = new int[n][n];
        for (int length = 2; length < n; length++) {
            for (int i = 0; i + length < n; i++) {
                int j = i + length;
                dp[i][j] = Integer.MAX_VALUE;
                for (int k = i + 1; k < j; k++) {
                    int cost = dp[i][k] + dp[k][j] + (cuts[j] - cuts[i]);
                    dp[i][j] = Math.min(dp[i][j], cost);
                }
                if (dp[i][j] == Integer.MAX_VALUE)
                    dp[i][j] = 0;
            }
        }
        return dp[0][n - 1];
    }
}

